import{_ as e,o as a,c as s,ag as i}from"./chunks/framework.DM0yugQT.js";const u=JSON.parse('{"title":"Cucumber","description":"","frontmatter":{},"headers":[],"relativePath":"cucumber.md","filePath":"cucumber.md"}'),d={name:"cucumber.md"};function o(r,t,l,n,h,c){return a(),s("div",null,[...t[0]||(t[0]=[i('<h1 id="cucumber" tabindex="-1">Cucumber <a class="header-anchor" href="#cucumber" aria-label="Permalink to &quot;Cucumber&quot;">​</a></h1><p>This documentation describes the technical aspects of our cucumber test suite.</p><ul><li>See also: <a href="./testing.html">on how to write Cucumber tests</a>.</li><li>See also: <a href="https://github.com/Project-OSRM/osrm-backend/wiki/Cucumber-Test-Suite" target="_blank" rel="noreferrer">about Cucumber in the OSRM wiki</a>.</li><li>See also: <a href="https://github.com/cucumber/cucumber-js/tree/main/docs" target="_blank" rel="noreferrer">the Cucumber docs</a>.</li></ul><h2 id="tl-dr" tabindex="-1">tl;dr <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;tl;dr&quot;">​</a></h2><p>Run the Cucumber tests with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --parallel</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 16</span></span></code></pre></div><h2 id="single-osrm-configuration" tabindex="-1">Single OSRM Configuration <a class="header-anchor" href="#single-osrm-configuration" aria-label="Permalink to &quot;Single OSRM Configuration&quot;">​</a></h2><p>An OSRM configuration consists of a <em>routing algorithm</em> and a <em>data load method</em>. OSRM currently supports the routing algorithms:</p><ul><li><code>ch</code> (Contraction Hierarchy), and</li><li><code>mld</code> (Multi-Level-Dijkstra)</li></ul><p>and the data load methods:</p><ul><li><code>directly</code> (load the files into memory),</li><li><code>mmap</code> (use memory mapped files), and</li><li><code>datastore</code> (use shared memory).</li></ul><p>To test all scenarios with a single OSRM configuration, say:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cucumber-js</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> home</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mld</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mmap</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --parallel</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --fail-fast</span></span></code></pre></div><p>Explanations follow:</p><h3 id="profiles" tabindex="-1">Profiles <a class="header-anchor" href="#profiles" aria-label="Permalink to &quot;Profiles&quot;">​</a></h3><p>Profiles are chosen with the <code>-p</code> commandline argument. Cucumber profiles allow you to change multiple configuration items with just one commandline argument. If you set more than one profile they are all merged into one configuration.</p><p>Note: Cucumber profiles should not be confused with OSRM profiles. Cucumber profiles are defined in <code>cucumber.mjs</code>. OSRM profiles reside in the <code>profiles/*.lua</code> files.</p><p>Our implementation offers following stock profiles. You should always use one base profile followed by zero or more additional profiles.</p><table tabindex="0"><thead><tr><th>Name</th><th></th></tr></thead><tbody><tr><td>home</td><td>Base profile to use on a developer machine</td></tr><tr><td>github</td><td>Base profile to use on the github CI server</td></tr><tr><td>ch</td><td>Additional profile that selects the CH algorithm</td></tr><tr><td>mld</td><td>Additional profile that selects the MLD algorithm</td></tr><tr><td>mmap</td><td>Additional profile that selects the mmap data load method</td></tr><tr><td>directly</td><td>Additional profile that selects the directly data load method</td></tr><tr><td>datastore</td><td>Additional profile that selects the datastore data load method</td></tr><tr><td>stress</td><td>Additional profile that selects only @stress tests</td></tr><tr><td>todo</td><td>Additional profile that selects only @todo tests</td></tr><tr><td>all</td><td>Additional profile that selects all tests</td></tr></tbody></table><h3 id="arguments" tabindex="-1">Arguments <a class="header-anchor" href="#arguments" aria-label="Permalink to &quot;Arguments&quot;">​</a></h3><p>Here is a <a href="https://github.com/cucumber/cucumber-js/blob/main/docs/configuration.md#options" target="_blank" rel="noreferrer">description of all arguments</a> you can pass to Cucumber. The interesting ones probably are: <code>--fail-fast</code>, <code>--format</code>, <code>--parallel</code>, and <code>--tags</code>.</p><p>Note: when using <code>--parallel N</code> make sure there are <code>N</code> contiguous free ports at the configured port number (eg. at ports 5000--5000+N).</p><h2 id="all-osrm-configurations" tabindex="-1">All OSRM Configurations <a class="header-anchor" href="#all-osrm-configurations" aria-label="Permalink to &quot;All OSRM Configurations&quot;">​</a></h2><p>We provide a shortcut to run all 6 configurations:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --parallel</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 16</span></span></code></pre></div><p>This is how the tests are run on the CI server. You can pass the same arguments as mentioned above.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>To speed up subsequent runs with the same parameters, the files generated by Cucumber and the by the OSRM extraction chain are held in a cache directory. This cache is located by default in <code>test/cache</code> and should be cleaned periodically:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test/cache</span></span></code></pre></div><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>The whole configuration is done in <code>cucumber.mjs</code>. You can either edit <code>worldParameters</code> in <code>cucumber.mjs</code> or use environment variables to override single defaults.</p><table tabindex="0"><thead><tr><th>worldParameters</th><th>Environment Variable</th><th>Defaults to</th><th></th></tr></thead><tbody><tr><td></td><td><code>CUCUMBER_TIMEOUT</code></td><td>5000</td><td>Scenario timeout in ms.</td></tr><tr><td><code>httpTimeout</code></td><td><code>CUCUMBER_HTTP_TIMEOUT</code></td><td>2000</td><td>HTTP timeout in ms.</td></tr><tr><td><code>testPath</code></td><td><code>CUCUMBER_TEST_PATH</code></td><td><code>test</code></td><td>The test directory</td></tr><tr><td><code>profilesPath</code></td><td><code>CUCUMBER_PROFILES_PATH</code></td><td><code>profiles</code></td><td>The profiles directory</td></tr><tr><td><code>logsPath</code></td><td><code>CUCUMBER_LOGS_PATH</code></td><td><code>test/logs</code></td><td>The logs directory</td></tr><tr><td><code>cachePath</code></td><td><code>CUCUMBER_CACHE_PATH</code></td><td><code>test/cache</code></td><td>The cache directory</td></tr><tr><td><code>buildPath</code></td><td><code>OSRM_BUILD_DIR</code></td><td><code>build</code></td><td>Path to the binaries</td></tr><tr><td><code>loadMethod</code></td><td><code>OSRM_LOAD_METHOD</code></td><td>datastore</td><td>Data load method</td></tr><tr><td><code>algorithm</code></td><td><code>OSRM_ALGORITHM</code></td><td>ch</td><td>Routing algorithm</td></tr><tr><td><code>ip</code></td><td><code>OSRM_IP</code></td><td>127.0.0.1</td><td>IP Address</td></tr><tr><td><code>port</code></td><td><code>OSRM_PORT</code></td><td>5000</td><td>IP Port</td></tr></tbody></table><p>The default Cucumber timeout can be changed by setting the environment variable <code>CUCUMBER_TIMEOUT</code>. This is discouraged, because the default timeout of 5 seconds is plenty for the problem sizes we are dealing with. The probable reasons for a test timing out are that <code>osrm-routed</code> died or that sync between <code>osrm-datastore</code> and <code>osrm-routed</code> was lost.</p><h3 id="other-environment-variables" tabindex="-1">Other environment variables <a class="header-anchor" href="#other-environment-variables" aria-label="Permalink to &quot;Other environment variables&quot;">​</a></h3><p><code>OSRM_RASTER_SOURCE</code> is set by &#39;Given the raster source&#39; and is supposed to be read back in your <code>profiles/*.lua</code> profile by <code>os.getenv(&#39;OSRM_RASTER_SOURCE&#39;)</code>.</p><p><code>OSRM_PROFILE</code> See: <a href="https://github.com/Project-OSRM/osrm-backend/pull/4516" target="_blank" rel="noreferrer">Pull Request #4516</a></p><h2 id="tags" tabindex="-1">Tags <a class="header-anchor" href="#tags" aria-label="Permalink to &quot;Tags&quot;">​</a></h2><p>Single scenarios or whole feature files can be tagged. Tag names can be selected arbitrarily although it is best to conform to the tags already used. Eg. the tag <code>@guidance</code> can be used to run only those tests related to the guidance feature:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --parallel</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 16</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tags</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @guidance</span></span></code></pre></div><p>We also support following special tags:</p><table tabindex="0"><thead><tr><th>Tag</th><th>A scenario thus tagged ...</th></tr></thead><tbody><tr><td><code>@isolated</code></td><td>will not run while any other scenario is running in parallel</td></tr><tr><td><code>@with_(datastore|directly|mmap)</code></td><td>will be executed iff the load method matches</td></tr><tr><td><code>@no_(datastore|directly|mmap)</code></td><td>will be executed unless the load method matches</td></tr><tr><td><code>@with_(ch|mld)</code></td><td>will be executed iff the algorithm matches</td></tr><tr><td><code>@no_(ch|mld)</code></td><td>will be executed unless the algorithm matches</td></tr><tr><td><code>@with_(linux|darwin|win32)</code></td><td>will be executed iff the OS matches</td></tr><tr><td><code>@no_(linux|darwin|win32)</code></td><td>will be executed unless the OS matches</td></tr></tbody></table><p>A test that calls <code>osrm-datastore --spring-clean</code> should not run concurrently with any other test, thus the tag <code>@isolated</code> should be applied. A test that runs or kills <code>osrm-routed</code> should not run while testing the datastore load method, and thus should be labeled with the tag <code>@no_datastore</code>.</p>',42)])])}const m=e(d,[["render",o]]);export{u as __pageData,m as default};
